private function pages(): void {SiteSection::query()->delete();SitePage::query()->delete();$pages=[['Home','home','home','Home','Prabhu Prakash Province, Nagpur','A responsive province website powered by Laravel and Filament CMS.','site/assets/img/st-vincent-pallotti.webp'],['St. Vincent Pallotti','st-vincent-pallotti','standard','About Us','St. Vincent Pallotti','Founder of the Society of the Catholic Apostolate and apostle of renewed faith and charity.','https://images.unsplash.com/photo-1523803326055-9729b9e02e5a?auto=format&fit=crop&w=1600&q=80'],['The Beginning','beginning','standard','About Us','The Beginning','The historical roots and growth of the Society of the Catholic Apostolate.','https://images.unsplash.com/photo-1523803326055-9729b9e02e5a?auto=format&fit=crop&w=1600&q=80'],['Milestones','milestones','timeline','About Us','Milestones in India','A visual timeline of Pallottine presence and growth in India.','https://images.unsplash.com/photo-1495020689067-958852a7765e?auto=format&fit=crop&w=1600&q=80'],['Local Communities','local-communities','standard','Administration','Local Communities','Communities that form the living network of the Province across mission and apostolic locations.','https://images.unsplash.com/photo-1523803326055-9729b9e02e5a?auto=format&fit=crop&w=1600&q=80'],['Commissions','commissions','standard','Administration','Commissions','Structured bodies that support provincial administration, apostolate and mission coordination.','https://images.unsplash.com/photo-1552664730-d307ca884978?auto=format&fit=crop&w=1600&q=80'],['Formation','formation','formation','Apostolic Works','Formation','Preparing candidates for future pastoral and apostolic service in the Society through prayer, study, accompaniment and community life.','site/assets/img/pallottine-75-years.webp'],['Education','education','standard','Apostolic Works','Education','Educational apostolates that form the young in faith, discipline and service.','https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&w=1600&q=80'],['Lay Animation','lay-animation','standard','Apostolic Works','Lay Animation','Animating the faithful to live their universal apostolic vocation.','https://images.unsplash.com/photo-1485217988980-11786ced9454?auto=format&fit=crop&w=1600&q=80'],['Parishes / Mission Stations','parishes','standard','Apostolic Works','Parishes / Mission Stations','Parish ministry and mission stations serving the people of God in diverse regions.','https://images.unsplash.com/photo-1519491050282-cf00c82424b4?auto=format&fit=crop&w=1600&q=80'],['Boys Homes','boys-homes','standard','Apostolic Works','Boys Homes','Homes and boarding initiatives that care for children and young people in need.','https://images.unsplash.com/photo-1488521787991-ed7bbaae773c?auto=format&fit=crop&w=1600&q=80'],['Social Apostolate','social-apostolate','standard','Apostolic Works','Social Apostolate','Service among the poor and marginalized through mission, development and solidarity.','https://images.unsplash.com/photo-1469571486292-b53601020f84?auto=format&fit=crop&w=1600&q=80'],['Contact Us','contact','contact','Contact','Contact Us','Reach the province office and stay connected with the Pallottine mission in Nagpur.','https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&w=1600&q=80']];$made=[];foreach($pages as $i=>$p){$made[$p[1]]=SitePage::create(['title'=>$p[0],'slug'=>$p[1],'template'=>$p[2],'hero_eyebrow'=>$p[3],'hero_title'=>$p[4],'hero_subtitle'=>$p[5],'hero_image'=>$p[6],'meta_title'=>$p[0],'meta_description'=>$p[5],'hero_style'=>'page-hero','status'=>1,'sort_order'=>$i+1]);}
$this->sec($made['home'],'welcome_strip','Welcome Strip','content','','','','Welcome to Prabhu Prakash Province, Nagpur. Birthdays, feast days and upcoming events will be updated here.');$this->sec($made['home'],'vision_mission','Vision & Mission','content','Vision & Mission','Revive faith and enkindle charity','','','site/assets/img/mary-queen-apostles.webp','Mary Queen of Apostles',items:[['title'=>'Vision','text'=>'To revive faith and enkindle charity in the entire world, collaborating with all people of good will to spread the Gospel of Christ.'],['title'=>'Mission','text'=>'To empower every member of the Church to become an apostle in their own sphere of life, fostering unity and renewal.']]);$this->sec($made['home'],'milestone','Milestone','content','Milestone','75 years of Pallottine Presence in India','','','site/assets/img/pallottine-75-years.webp','75 years of Pallottine Presence in India');$this->sec($made['home'],'leadership','Leadership','content','Provincial Administration','Guided by dedicated leadership');$this->sec($made['home'],'stats','Stats','content','Province at a Glance','Members and formation',items:[['icon'=>'fa-solid fa-cross','label'=>'Priests','count'=>133],['icon'=>'fa-solid fa-handshake-angle','label'=>'Brotherhood','count'=>2],['icon'=>'fa-solid fa-award','label'=>'Finally Professed','count'=>4],['icon'=>'fa-solid fa-seedling','label'=>'In Formation','count'=>112]]);$this->sec($made['home'],'videos','Videos','content','Pallotti Media Vision','Watch, reflect and stay connected',settings:['button_url'=>'https://www.youtube.com/','button_label'=>'More Videos']);$this->sec($made['home'],'recent_updates','Recent Updates','content','Updates','Recent Events');$this->cta($made['home']);
$this->std($made['st-vincent-pallotti'],'St. Vincent Pallotti',['Born in Rome on 21 April 1795, St. Vincent Pallotti was a diocesan priest with a profound vision that every baptized person is called to participate in the mission of the Church.','He founded the Union of the Catholic Apostolate and the Society of the Catholic Apostolate in 1835, bringing together priests, brothers and lay faithful for the proclamation of the Gospel.','His motto, "The love of Christ urges us on", continues to inspire Pallottines across the world in prayer, fraternity and selfless service.'],[['icon'=>'fa-solid fa-church','title'=>'Founder','text'=>'Founded the Society of the Catholic Apostolate in Rome in 1835.'],['icon'=>'fa-solid fa-crown','title'=>'Patroness','text'=>'Mary Queen of Apostles remains central to Pallottine spirituality.'],['icon'=>'fa-solid fa-star','title'=>'Canonized','text'=>'Canonized on 20 January 1963 by Pope John XXIII.']]);
$this->std($made['beginning'],'The Beginning',['Saint Vincent Pallotti founded the Society as a community of priests and brothers in Rome in 1835.','From its earliest years, collaborators from different nations shared in Pallotti\'s vision of apostolic communion.','The Society grew through changing times, eventually restoring its original name in 1947 and rediscovering the founder\'s vision in the Extraordinary General Chapter of 1968.'],[['icon'=>'fa-solid fa-landmark','title'=>'1835 Foundation','text'=>'A community founded in Rome for the revival of faith and rekindling of charity.'],['icon'=>'fa-solid fa-earth-asia','title'=>'International Spirit','text'=>'Early collaborators came from different nations, reflecting Pallotti\'s wider vision.'],['icon'=>'fa-solid fa-seedling','title'=>'Renewed Charism','text'=>'The Society continues to renew the apostolic call of all the faithful.']]);
$this->sec($made['milestones'],'timeline','Timeline','timeline','Timeline','75 years of Pallottine presence',items:[['year'=>'1951','text'=>'The first two German missionaries arrived in Bombay and proceeded to Nagpur and Raipur.'],['year'=>'1955','text'=>'Foundation of the Christsevikas of the Society of the Catholic Apostolate.'],['year'=>'1956','text'=>'First novitiate house for Indian Pallottines was established in Raipur.'],['year'=>'1957','text'=>'The first Pallottine school in India, Holy Cross School, Byron Bazar, Raipur.'],['year'=>'1959','text'=>'First Indian priest was ordained and the first Indian Pallottine brother made profession.'],['year'=>'1961','text'=>'The Pallottine Delegature was officially established in India.'],['year'=>'1964','text'=>'Msgr. Hans Weidner was appointed first Prefect Apostolic of Raipur.'],['year'=>'1981','text'=>'Pallottigiri was established as a formation centre.'],['year'=>'1988','text'=>'The Pallottines established Northern Delegature.']]);$this->cta($made['milestones']);
foreach([['local-communities','Local Communities',['The Prabhu Prakash Province is composed of local communities rooted in fraternity, apostolic service and shared responsibility.','Local communities express the Pallottine charism through prayer, ministry, pastoral collaboration and mission outreach.'],[['icon'=>'fa-solid fa-house-chimney','title'=>'Pallotti Bhawan, Nagpur','text'=>'A major community and provincial centre located at Seminary Hills, Nagpur.'],['icon'=>'fa-solid fa-mountain-sun','title'=>'Pallotti Sadan, Idukki','text'=>'A formation-linked community located in the mountain ranges of Idukki.'],['icon'=>'fa-solid fa-people-roof','title'=>'Mission Communities','text'=>'Communities serving in various pastoral, educational and social apostolate locations.']]],['commissions','Commission Structure',['The commissions are auxiliary bodies of the Provincial Administration, helping the Province plan, coordinate and evaluate important areas of mission.','Each commission supports a particular field, from spirituality and formation to education, finance, pastoral ministry, youth, social apostolate and media communication.'],[['icon'=>'fa-solid fa-users-gear','title'=>'Spiritual Animation','text'=>'Supports spiritual renewal, prayer and animation in the Province.'],['icon'=>'fa-solid fa-users-gear','title'=>'Education Board','text'=>'Formulates policies, evaluates institutions and guides educational initiatives.'],['icon'=>'fa-solid fa-users-gear','title'=>'Finance Commission','text'=>'Plans, monitors and coordinates financial management of the Province.']]],['education','Education',['The Province participates in the educational mission of the Church by forming young minds and hearts in truth, discipline and service.','Schools and educational initiatives become spaces of human development, leadership and Christian witness in society.'],[['icon'=>'fa-solid fa-school','title'=>'Schools','text'=>'Educational institutions committed to quality learning and value formation.'],['icon'=>'fa-solid fa-book-open-reader','title'=>'Holistic Formation','text'=>'Education that fosters intellectual, moral and spiritual growth.'],['icon'=>'fa-solid fa-people-group','title'=>'Community Impact','text'=>'Schools that serve families and local communities with dedication.']]],['lay-animation','Lay Animation',['St. Vincent Pallotti believed that the saving mission of the Church belongs to all the faithful.','Only through close cooperation of priests and lay people can evangelization flourish. The Province continues this dream through animation centres and apostolic formation.'],[['icon'=>'fa-solid fa-people-group','title'=>'Pallottine Animation Centre','text'=>'Centre in Nagpur for lay animation and apostolic renewal.'],['icon'=>'fa-solid fa-hands-holding-circle','title'=>'Mariarani Center','text'=>'Animation centre in Thiruvananthapuram supporting formation and service.'],['icon'=>'fa-solid fa-dove','title'=>'Sehion','text'=>'A centre committed to prayer, mission and lay participation.']]],['parishes','Parishes / Mission Stations',['Parish ministry and mission stations are key expressions of the Province\'s pastoral service among the people of God.','Through sacramental life, catechesis, accompaniment and outreach, these centres sustain faith communities in urban and rural settings.'],[['icon'=>'fa-solid fa-church','title'=>'Parish Ministry','text'=>'Pastoral care through liturgy, catechesis and community accompaniment.'],['icon'=>'fa-solid fa-map-location-dot','title'=>'Mission Stations','text'=>'Outreach in mission regions where the Church accompanies growing communities.'],['icon'=>'fa-solid fa-cross','title'=>'Faith Formation','text'=>'Continuing formation for children, youth and families in parish life.']]],['boys-homes','Boys Homes',['St. Vincent Pallotti fought against the neglect of children and opened homes for the unskilled and homeless.','The Province continues this work of charity through boys homes and boarding schools in different parts of the country.'],[['icon'=>'fa-solid fa-child-reaching','title'=>'Boarding School, Aulia','text'=>'Aulia Koladit P.O., Via Pandhana, Khandwa District, Madhya Pradesh.'],['icon'=>'fa-solid fa-house-user','title'=>'Boarding School, Ishgarh','text'=>'Boarding School, Ishgarh, Pipilia P.O., Jhabua, Madhya Pradesh.']]],['social-apostolate','Social Apostolate',['The social apostolate of the Province reaches out to the poor and marginalized with compassion, justice and practical solidarity.','Through service projects, mission outreach and community collaboration, the Province witnesses to the Gospel in daily life.'],[['icon'=>'fa-solid fa-hand-holding-heart','title'=>'Social Outreach','text'=>'Supporting vulnerable people through mission and service programmes.'],['icon'=>'fa-solid fa-seedling','title'=>'Development Initiatives','text'=>'Human development projects that strengthen families and communities.'],['icon'=>'fa-solid fa-people-arrows','title'=>'Solidarity','text'=>'Collaboration with local communities for sustainable change and dignity.']]]] as $d){$this->std($made[$d[0]],$d[1],$d[2],$d[3]);}
$this->sec($made['formation'],'intro','Formation Intro','content','Overview','A formation journey rooted in faith and mission','','<p>St. Vincent Pallotti gave great attention to religious formation, spiritual accompaniment and preparation for apostolic activity.</p><p>The Province runs centres of formation where candidates are prepared for future pastoral and apostolic work in the Society.</p>');$this->sec($made['formation'],'sidebar','Formation Sidebar','sidebar','Formation Contact','Formation Centres','A reference-inspired address panel for the key formation houses, styled to match the current premium province website.',items:[['icon'=>'fa-solid fa-location-dot','title'=>'Pallottigiri','text'=>"Monvila, Kulathoor P.O.\nThiruvananthapuram, Kerala, India"],['icon'=>'fa-solid fa-building','title'=>'Casa Pallotti','text'=>"Umran, Shillong\nMeghalaya, India"],['icon'=>'fa-solid fa-house-chimney','title'=>'Pallotti Bhawan','text'=>"Seminary Hills\nNagpur, Maharashtra, India"],['icon'=>'fa-solid fa-phone','title'=>'Province Contact','text'=>"+91 9503505802\nnapallottines@gmail.com"]]);$this->sec($made['formation'],'centres','Formation Centres','cards','List of Formation Centres','Formation houses and study centres',items:[['title'=>'Pallottigiri','text'=>'Vocation Orientation Centre for Kerala, North and North East of India, serving as an important early stage of discernment and accompaniment.','image'=>'site/assets/img/event-jubilee.webp'],['title'=>'Casa Pallotti','text'=>'Minor seminary in Umran, Shillong, dedicated to the initial formation of students from the Northeast in a setting of prayer, study and community living.','image'=>'site/assets/img/event-pallotti-media.webp'],['title'=>'Pallotti Bhawan','text'=>'A major house of formation at Seminary Hills, Nagpur, supporting candidates through a disciplined life of fraternity, study and spiritual growth.','image'=>'site/assets/img/mary-queen-apostles.webp']]);$this->sec($made['formation'],'note','Formation Note','content','Pallottine Spirit','The love of Christ urges us on','','Formation in the Province is shaped by prayer, fraternity and generous apostolic availability so that candidates grow into faithful servants of the Church.',settings:['icon'=>'fa-solid fa-cross']);$this->sec($made['contact'],'contact_details','Contact Details','contact','Province Office','Pallotti Bhawan',items:[['icon'=>'fa-solid fa-location-dot','title'=>'Address','text'=>'Pallotti Bhawan, Seminary Hills, Nagpur, Maharashtra, India'],['icon'=>'fa-solid fa-phone','title'=>'Phone','text'=>"+91 9503505802\n+91 9074515998"],['icon'=>'fa-solid fa-envelope','title'=>'Email','text'=>"napallottines@gmail.com\nroswanherald@gmail.com"],['icon'=>'fa-solid fa-globe','title'=>'Website','text'=>'www.napallottines.org']]);}
