private function std(SitePage $p,string $t,array $ps,array $items): void {$html=collect($ps)->map(fn($x)=>'<p class="text-slate-600 leading-8 mb-4">'.e($x).'</p>')->implode('');$this->sec($p,'overview','Overview','content','Overview',$t,'',$html,settings:['icon'=>'fa-solid fa-cross','card_title'=>'The love of Christ urges us on','card_text'=>'A mission of prayer, fraternity and selfless service for the renewal of faith and charity.']);$this->sec($p,'highlights','Highlights','cards','Highlights','Key Details',items:$items);$this->cta($p);}private function cta(SitePage $p): void {$this->sec($p,'cta','Call To Action','cta','Stay Connected','Join the mission of faith, service and communion.','','Explore our communities, apostolic works and provincial initiatives through this complete responsive website template.',settings:['button_url'=>'/contact','button_label'=>'Contact Province']);}
